// Runtime overrides
const overrides: Partial<Record<EntityName, Partial<EntityConfig>>> = {}

/**
 * Get configuration for an entity.
 */
export function getEntityConfig(entity: EntityName): EntityConfig {
  return {
    ...defaultConfig[entity],
    ...overrides[entity],
  }
}

/**
 * Get the sync mode for an entity.
 */
export function getSyncMode(entity: EntityName): SyncMode {
  return getEntityConfig(entity).syncMode
}

/**
 * Check if entity uses offline persistence (IndexedDB).
 */
export function isOfflineEnabled(entity: EntityName): boolean {
  return getSyncMode(entity) === 'offline'
}

/**
 * Override entity configuration at runtime.
 *
 * Note: Runtime switching between sync modes only works for api <-> electric.
 * Offline mode requires the Dexie bridge to be initialized at startup.
 */
export function setEntityConfig(
  entity: EntityName,
  config: Partial<EntityConfig>
): void {
  overrides[entity] = { ...overrides[entity], ...config }
}

/**
 * Reset all runtime overrides.
 */
export function resetEntityConfig(): void {
  for (const key of Object.keys(overrides)) {
    delete overrides[key as EntityName]
  }
}

/**
 * Get all entities with offline mode enabled.
 */
export function getOfflineEntities(): EntityName[] {
  const entities: EntityName[] = []
  for (const [entity, config] of Object.entries(defaultConfig)) {
    if (config.syncMode === 'offline') {
      entities.push(entity as EntityName)
    }
  }
  return entities
}